function budget_table_tdp_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('budget_table_tdp');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'project_id' => Request::lookup('project_id', ''),
		'title_of_the_project' => br2nl(Request::val('title_of_the_project', '')),
		'name_of_pi' => Request::val('name_of_pi', ''),
		'institute' => Request::val('institute', ''),
		'date_of_presentation' => Request::dateComponents('date_of_presentation', ''),
		'manpower' => Request::val('manpower', ''),
		'travel' => Request::val('travel', ''),
		'infrastructure' => Request::val('infrastructure', ''),
		'consumables' => Request::val('consumables', ''),
		'contigency' => Request::val('contigency', ''),
		'overhead' => Request::val('overhead', ''),
		'any_other' => Request::val('any_other', ''),
		'total_budget' => Request::val('total_budget', ''),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('budget_table_tdp', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		budget_table_tdp_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function budget_table_tdp_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function budget_table_tdp_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('budget_table_tdp', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: budget_table_tdp_before_delete
	if(function_exists('budget_table_tdp_before_delete')) {
		$args = [];
		if(!budget_table_tdp_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `budget_table_tdp` WHERE `id`='{$selected_id}'", $eo);

	// hook: budget_table_tdp_after_delete
	if(function_exists('budget_table_tdp_after_delete')) {
		$args = [];
		budget_table_tdp_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='budget_table_tdp' AND `pkValue`='{$selected_id}'", $eo);
}

function budget_table_tdp_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('budget_table_tdp', $selected_id, 'edit')) return false;

	$data = [
		'project_id' => Request::lookup('project_id', ''),
		'title_of_the_project' => br2nl(Request::val('title_of_the_project', '')),
		'name_of_pi' => Request::val('name_of_pi', ''),
		'institute' => Request::val('institute', ''),
		'date_of_presentation' => Request::dateComponents('date_of_presentation', ''),
		'manpower' => Request::val('manpower', ''),
		'travel' => Request::val('travel', ''),
		'infrastructure' => Request::val('infrastructure', ''),
		'consumables' => Request::val('consumables', ''),
		'contigency' => Request::val('contigency', ''),
		'overhead' => Request::val('overhead', ''),
		'any_other' => Request::val('any_other', ''),
		'total_budget' => Request::val('total_budget', ''),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('budget_table_tdp', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: budget_table_tdp_before_update
	if(function_exists('budget_table_tdp_before_update')) {
		$args = ['old_data' => $old_data];
		if(!budget_table_tdp_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'budget_table_tdp',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="budget_table_tdp_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('budget_table_tdp', $data['selectedID'], calculated_fields()['budget_table_tdp']);

	// hook: budget_table_tdp_after_update
	if(function_exists('budget_table_tdp_after_update')) {
		if($row = getRecord('budget_table_tdp', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!budget_table_tdp_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('budget_table_tdp', $selected_id);
}

